  1	import * as React from 'react';
  2	import { NooBaaObjectBucketClaimModel } from '@odf/shared';
  3	import { formSettings } from '@odf/shared/constants';
  4	import ResourceDropdown from '@odf/shared/dropdown/ResourceDropdown';
  5	import { FormGroupController } from '@odf/shared/form-group-controller';
  6	import { ButtonBar } from '@odf/shared/generic/ButtonBar';
  7	import { LoadingBox } from '@odf/shared/generic/status-box';
  8	import { useK8sGet } from '@odf/shared/hooks/k8s-get-hook';
  9	import { DeploymentModel } from '@odf/shared/models';
 10	import { getName, getNamespace } from '@odf/shared/selectors';
 11	import { DeploymentKind } from '@odf/shared/types';
 12	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 13	import { referenceForModel, resourcePathFromModel } from '@odf/shared/utils';
 14	import { useYupValidationResolver } from '@odf/shared/yup-validation-resolver';
 15	import {
 16	  k8sCreate,
 17	  K8sKind,
 18	  k8sPatch,
 19	} from '@openshift-console/dynamic-plugin-sdk';
 20	import { useForm } from 'react-hook-form';
 21	import { useParams, useNavigate } from 'react-router-dom-v5-compat';
 22	import * as Yup from 'yup';
 23	import {
 24	  Alert,
 25	  Form,
 26	  FormGroup,
 27	  Radio,
 28	  ActionGroup,
 29	  Button,
 30	} from '@patternfly/react-core';
 31	import { getAttachOBCPatch } from '../../utils';
 32	import { CreateOBCForm } from '../mcg/CreateObjectBucketClaim';
 33	import { commonReducer, defaultState } from '../mcg/state';
 34	import '../../style.scss';
 35	import useObcFormSchema from '../mcg/useObcFormSchema';
 36	
 37	const AttachStorage: React.FC<AttachStorageProps> = (props) => {
 38	  const navigate = useNavigate();
 39	  const { t } = useCustomTranslation();
 40	  const [state, dispatch] = React.useReducer(commonReducer, defaultState);
 41	  const [createOBC, setCreateOBC] = React.useState<boolean>(false);
 42	  const [selectedOBC, setSelectedOBC] = React.useState<string>(null);
 43	  const { kindObj, namespace, resourceName } = props;
 44	
 45	  const [deployment, loaded, loadError] = useK8sGet<DeploymentKind>(
 46	    kindObj,
 47	    resourceName,
 48	    namespace
 49	  );
 50	
 51	  const { obcFormSchema, fieldRequirements } = useObcFormSchema(
 52	    namespace,
 53	    state
 54	  );
 55	
 56	  const schema = !createOBC
 57	    ? Yup.object({
 58	        existing: Yup.string().required(),
 59	      })
 60	    : obcFormSchema;
 61	
 62	  const resolver = useYupValidationResolver(schema);
 63	
 64	  const {
 65	    control,
 66	    handleSubmit,
 67	    watch,
 68	    formState: { isValid, isSubmitted },
 69	  } = useForm({ ...formSettings, resolver });
 70	
 71	  const obcName: string = watch('obcName');
 72	  React.useEffect(() => {
 73	    if (createOBC) {
 74	      dispatch({ type: 'setName', name: obcName });
 75	    }
 76	  }, [obcName, createOBC, dispatch]);
 77	
 78	  const onSubmit = async (_unused, e: { preventDefault: () => void }) => {
 79	    e.preventDefault();
 80	    try {
 81	      let obc = selectedOBC;
 82	      dispatch({ type: 'setProgress' });
 83	      if (createOBC) {
 84	        const obj = await k8sCreate({
 85	          model: NooBaaObjectBucketClaimModel,
 86	          data: state.payload,
 87	        });
 88	        obc = getName(obj);
 89	      }
 90	      const patch = getAttachOBCPatch(obc, deployment);
 91	      const patchedObj = await k8sPatch({
 92	        model: DeploymentModel,
 93	        resource: deployment,
 94	        data: patch,
 95	      });
 96	      navigate(
 97	        `${resourcePathFromModel(
 98	          DeploymentModel,
 99	          getName(patchedObj),
100	          getNamespace(patchedObj)
101	        )}/environment`
102	      );
103	    } catch (err) {
104	      dispatch({ type: 'unsetProgress' });
105	      dispatch({ type: 'setError', message: err.message });
106	    }
107	  };
108	
109	  const onRadioToggle = () => setCreateOBC((val) => !val);
110	
111	  return (
112	    <Form
113	      onSubmit={handleSubmit(onSubmit)}
114	      className="odf-m-pane__body-group odf-m-pane__form"
115	    >
116	      <FormGroup fieldId="attach-obc">
117	        <Radio
118	          label={t('Use existing claim')}
119	          value="exists"
120	          key="exists"
121	          onChange={onRadioToggle}
122	          id="exists"
123	          name="exists"
124	          isChecked={!createOBC}
125	        />
126	        {!createOBC && (
127	          <FormGroupController
128	            control={control}
129	            name="existing"
130	            formGroupProps={{
131	              fieldId: 'existing',
132	              label: t('ObjectBucketClaim'),
133	              isRequired: true,
134	              className: 'pf-v6-u-ml-lg',
135	            }}
136	            render={({ onChange }) => (
137	              <ResourceDropdown
138	                id="existing"
139	                initialSelection={(resources) =>
140	                  resources?.find((res) => getName(res) === selectedOBC)
141	                }
142	                resourceModel={NooBaaObjectBucketClaimModel}
143	                resource={{
144	                  kind: referenceForModel(NooBaaObjectBucketClaimModel),
145	                  namespace,
146	                  namespaced: true,
147	                  isList: true,
148	                }}
149	                onSelect={(item) => {
150	                  const name = getName(item);
151	                  setSelectedOBC(name);
152	                  onChange(name);
153	                }}
154	              />
155	            )}
156	          />
157	        )}
158	        <Radio
159	          label={t('Create new claim')}
160	          value="create"
161	          key="create"
162	          onChange={onRadioToggle}
163	          id="create"
164	          name="create"
165	          isChecked={createOBC}
166	          className="pf-v6-u-mt-sm"
167	        />
168	        {createOBC && (
169	          <div className="pf-v6-u-ml-lg">
170	            <CreateOBCForm
171	              state={state}
172	              dispatch={dispatch}
173	              namespace={namespace}
174	              control={control}
175	              fieldRequirements={fieldRequirements}
176	            />
177	          </div>
178	        )}
179	      </FormGroup>
180	      {!isValid && isSubmitted && (
181	        <Alert
182	          variant="danger"
183	          isInline
184	          title={t('Address form errors to proceed')}
185	        />
186	      )}
187	      <ButtonBar
188	        errorMessage={state.error || loadError?.message}
189	        inProgress={state.progress}
190	      >
191	        <ActionGroup className="pf-v6-c-form">
192	          <Button
193	            type="submit"
194	            variant="primary"
195	            isDisabled={loadError || !loaded || state.progress}
196	          >
197	            {t('Create')}
198	          </Button>
199	          <Button
200	            onClick={() => navigate(-1)}
201	            type="button"
202	            variant="secondary"
203	          >
204	            {t('Cancel')}
205	          </Button>
206	        </ActionGroup>
207	      </ButtonBar>
208	    </Form>
209	  );
210	};
211	
212	const AttachStorageWrapper: React.FC<AttachStorageWrapperProps> = (props) => {
213	  const { kindObj, kindsInFlight } = props;
214	  const params = useParams();
215	
216	  return !kindObj && kindsInFlight ? (
217	    <LoadingBox />
218	  ) : (
219	    <AttachStorage
220	      namespace={params.ns}
221	      resourceName={params.name}
222	      {...props}
223	    />
224	  );
225	};
226	
227	type AttachStorageWrapperProps = {
228	  kindObj: K8sKind;
229	  kindsInFlight: any;
230	};
231	
232	type AttachStorageProps = AttachStorageWrapperProps & {
233	  namespace: string;
234	  resourceName: string;
235	};
236	
237	export default AttachStorageWrapper;

